const body = $input.item.json.body || {};
const text = (body.text || '').trim().toLowerCase();
const user = body.user_name || 'unknown';
const channel = body.channel_id || '#stb-automation';

// Parse: /stb-test [markers] [--workers N] [--reruns N]
let markers = 'smoke';
let workers = 0;
let reruns = 2;

const parts = text.split(/\s+/);
if (parts[0] && !parts[0].startsWith('--')) {
  markers = parts[0];
}
const workersFlag = text.match(/--workers\s+(\d+)/);
if (workersFlag) workers = parseInt(workersFlag[1]);
const rerunsFlag = text.match(/--reruns\s+(\d+)/);
if (rerunsFlag) reruns = parseInt(rerunsFlag[1]);

return [{ json: { markers, workers, reruns, user, channel, raw_text: text } }];

