const s = $input.item.json;
const icon  = s.failed === 0 && s.errors === 0 ? '✅' : '❌';
const color = s.failed === 0 && s.errors === 0 ? 'good' : 'danger';
const user  = $('Parse Slack Command').item.json.user;
const markers = $('Parse Slack Command').item.json.markers;

const text = `${icon} *STB Test Results* (triggered by @${user})

• Markers: \`${markers}\`
• Total: ${s.total} | ✅ ${s.passed} | ❌ ${s.failed} | ⚠️ ${s.errors}
• Pass Rate: *${s.pass_pct}%*

📊 Dashboard: http://localhost:8501`;

return [{ json: { text, color } }];
